// EP-42: heuristic search for M=3 obstruction at N=110.
{
  const N = 110;
  const M = 3;
  const rng = makeRng(20260304 ^ 42);

  function sidonRandomSize(k, attempts = 50) {
    let best = [];
    for (let t = 0; t < attempts; t += 1) {
      const A = sidonGreedyRandom(N, k, rng, 8);
      if (A.length > best.length) best = A;
      if (best.length >= k) break;
    }
    return best;
  }

  function scoreA(A) {
    const diffs = new Uint8Array(N);
    for (let i = 0; i < A.length; i += 1) {
      for (let j = i + 1; j < A.length; j += 1) diffs[A[j] - A[i]] = 1;
    }
    const C = [];
    for (let d = 1; d < N; d += 1) if (!diffs[d]) C.push(d);
    // Count Schur triples in C: a<b, a+b in C.
    const inC = new Uint8Array(N);
    for (const x of C) inC[x] = 1;
    let bad = 0;
    for (let i = 0; i < C.length; i += 1) {
      const a = C[i];
      for (let j = i + 1; j < C.length; j += 1) {
        const b = C[j];
        const s = a + b;
        if (s >= N) break;
        if (inC[s]) bad += 1;
      }
    }
    return { bad, C_size: C.length };
  }

  let best = { bad: Infinity, A: [] };
  const restarts = 40;
  const steps = 1500;
  const k = 12;

  for (let r = 0; r < restarts; r += 1) {
    let A = sidonRandomSize(k, 20);
    if (A.length < k) continue;
    let cur = scoreA(A);
    for (let s = 0; s < steps; s += 1) {
      const idx = Math.floor(rng() * A.length);
      const old = A[idx];
      const cand = 1 + Math.floor(rng() * N);
      if (A.includes(cand)) continue;
      A[idx] = cand;
      A.sort((a, b) => a - b);
      if (!isSidon(A)) {
        A[idx] = old;
        A.sort((a, b) => a - b);
        continue;
      }
      const sc = scoreA(A);
      const accept = sc.bad <= cur.bad || rng() < Math.exp((cur.bad - sc.bad) / 5);
      if (accept) {
        cur = sc;
      } else {
        A[idx] = old;
        A.sort((a, b) => a - b);
      }
    }
    if (cur.bad < best.bad) best = { bad: cur.bad, A: A.slice(), C_size: cur.C_size };
  }

  out.results.ep42 = {
    description: 'Heuristic Sidon A search at N=110 targeting M=3 obstruction via sum-free complement.',
    N,
    M,
    best_bad: best.bad,
    best_C_size: best.C_size,
    best_A: best.A,
  };
}
